SELECT NVL(MAX(va.admin_ck), 'N')
FROM vw_user_auth va
WHERE va.project_code = #{projectCode}
  AND va.user_code = #{userCode}

SELECT wl.work_log_code AS "workLogCode", wl.issue_code AS "issueCode", i.title AS "issueTitle", p.project_code AS "projectCode", p.project_name AS "projectName", p.status AS "projectStatus", i.type_code AS "typeCode", t.type_name AS "typeName", wl.worker_code AS "workerCode", u.name AS "workerName", TO_CHAR(wl.work_date, 'YYYY-MM-DD') AS "workDate", wl.spent_minutes AS "spentMinutes", wl.description AS "description" FROM work_logs wl JOIN issues i ON i.issue_code = wl.issue_code JOIN projects p ON p.project_code = i.project_code JOIN users u ON u.user_code = wl.worker_code LEFT JOIN types t ON t.type_code = i.type_code WHERE wl.work_log_code = #{workLogCode} AND
p.project_code IN
#{code}
AND p.status IN ('OD1', 'OD3')
(
( p.project_code IN
#{code}
AND p.status IN ('OD1', 'OD3') )
OR
( p.project_code IN
#{code}
AND p.status = 'OD1' )
)
